{
  "premium_report": {
    "report_title": "프리미엄 사주 스토리",
    "version": "1.0",
    "sections": [
      {
        "section_id": "section_1",
        "category": "overall",
        "title": "프리미엄 사주 스토리",
        "headline": "말과 생각의 흐름을 정돈하는 태도",
        "summary_lines": [
          "다양한 상황에서 판단의 흐름이 점진적으로 정비되며 같은 상황도 다르게 읽힐 수 있습니다.",
          "타인과의 관계에서 기대치를 확인하는 시간을 가지면 갈등 가능성을 낮추고 말의 흐름을 안정적으로 이끌 수 있습니다.",
          "현재 흐름은 목표를 향해 차분하게 움직여 중요한 순간에 선택의 폭을 유지하는 편입니다."
        ],
        "core_insight": "당신은 여러 선택지가 열려 있을 때도 마음속 정리를 먼저 하는 편이라 같은 상황에서도 판단의 흐름이 달라질 수 있습니다. 이 차이를 이해하면 불필요한 갈등을 줄이고 필요한 부분에 집중하기 쉽습니다. 현재 흐름은 일정한 리듬으로 성과를 만들어 가려는 방향이며 말의 순서를 다듬는 일이 의사소통의 흐름을 매끄럽게 만듭니다. 관계를 다룰 때는 상대의 기대와 나의 기준 사이에서 균형을 찾아가는 과정이 중요합니다. 때로는 과거의 기억이 현재 선택에 스며들 때가 있지만 그것을 현명하게 살피면 방향이 더 명확해집니다.",
        "strength": "사려 깊은 판단 흐름과 말의 순서를 다듬는 습관이, 복잡한 상황에서도 관계의 흐름이 매끄럽게 이어지도록 돕습니다.",
        "risk": "선택지의 폭이 넓어 실행 시기가 늦춰질 수 있어, 속도와 선호의 균형을 신경 쓰는 것이 중요합니다.",
        "action_points": [
          "중요한 판단은 여러 각도에서 확인한 뒤 내리세요.",
          "관계가 가까워질수록 상대의 기대를 함께 확인하고 공유하세요.",
          "일과 삶의 균형을 맞추려는 계획을 먼저 세우고 실천에 옮기세요."
        ],
        "action_note": "현재 흐름은 대화의 순서를 먼저 점검하고, 상대의 기대를 확인하는 시간을 가지는 것이 효과적입니다."
      }
    ]
  }
}
